module AStarHeuristic (
    input [3:0] g, // cost from start to current node
    input [3:0] h, // heuristic cost to goal node
    output [3:0] f  // total estimated cost
);
      wire _n01 = g[0] ^ h[0];
  wire _c01 = g[0] & h[0];
  wire _n02 = g[1] ^ h[1] ^ _c01;
  wire _c02 = (g[1] & h[1]) | (g[1] & _c01) | (h[1] & _c01);
  wire _n03 = g[2] ^ h[2] ^ _c02;
  wire _c03 = (g[2] & h[2]) | (g[2] & _c02) | (h[2] & _c02);
  wire _n04 = g[3] ^ h[3] ^ _c03;
  wire _c04 = (g[3] & h[3]) | (g[3] & _c03) | (h[3] & _c03);
  assign f = {_n01, _n02, _n03, _n04}; // f = g + h
endmodule
